#include <stdio.h>
#include <stdlib.h>

#define MIN_CAPACITY 4

typedef struct {
    int *array;      // Dynamic array pointer
    int capacity;    // Current array capacity
    int top;         // Index of top element (-1 if empty)
} DynamicStack;

// Initialize stack with initial capacity
DynamicStack* initStack() {
    DynamicStack *stack = (DynamicStack*)malloc(sizeof(DynamicStack));
    if (stack == NULL) {
        return NULL;  // Memory allocation failed
    }
    stack->array = (int*)malloc(MIN_CAPACITY * sizeof(int));
    if (stack->array == NULL) {
        free(stack);
        return NULL;
    }
    stack->capacity = MIN_CAPACITY;
    stack->top = -1;
    return stack;
}

// Check if stack is empty
int isEmpty(DynamicStack *stack) {
    return stack->top == -1;
}

// Destroy stack and free memory
void destroyStack(DynamicStack *stack) {
    if (stack != NULL) {
        free(stack->array);
        free(stack);
    }
}

// Resize function - internal helper
int resize(DynamicStack *stack, int newCapacity) {
    int *newArray = (int*)realloc(stack->array, newCapacity * sizeof(int));
    if (newArray == NULL) {
        return 0;  // Resize failed
    }
    stack->array = newArray;
    stack->capacity = newCapacity;
    return 1;  // Success
}

// Push with doubling strategy
int push(DynamicStack *stack, int element) {
    if (stack == NULL) return 0;

    // Check if resize needed (stack full)
    if (stack->top >= stack->capacity - 1) {
        int newCapacity = stack->capacity * 2;
        if (!resize(stack, newCapacity)) {
            return 0;  // Resize failed
        }
    }

    // Increment top and store element
    stack->array[++stack->top] = element;
    return 1;  // Success
}

// Peek - view top element without removing
int peek(DynamicStack *stack, int *element) {
    if (stack == NULL || isEmpty(stack)) {
        return 0;  // Stack empty or NULL
    }
    *element = stack->array[stack->top];
    return 1;
}

// Pop with shrink-to-fit
int pop(DynamicStack *stack, int *element) {
    if (stack == NULL || isEmpty(stack)) {
        return 0;  // Stack underflow
    }

    // Get element at top
    *element = stack->array[stack->top--];

    // Shrink if utilization drops below 25%
    // But maintain minimum capacity
    int currentSize = stack->top + 1;  // Number of elements
    if (currentSize < stack->capacity / 4 && 
        stack->capacity > MIN_CAPACITY) {
        int newCapacity = stack->capacity / 2;
        if (newCapacity < MIN_CAPACITY) {
            newCapacity = MIN_CAPACITY;
        }
        resize(stack, newCapacity);
    }

    return 1;  // Success
}

// Get current number of elements
int getSize(DynamicStack *stack) {
    if (stack == NULL) return 0;
    return stack->top + 1;
}

// Get current capacity
int getCapacity(DynamicStack *stack) {
    if (stack == NULL) return 0;
    return stack->capacity;
}
